import React, { useState, useEffect } from "react";
import axios from "axios";

const PortForm = () => {
  const [url, setUrl] = useState("");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchData = async () => {
    const res = await axios.get("http://localhost:5000/api/all");
    setData(res.data);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!url) {
      setError("Please enter URL");
      return;
    }

    try {
      setLoading(true);
      setError("");

      await axios.post("http://localhost:5000/api/add", { url });

      setUrl("");
      fetchData();

    } catch (err) {
      setError("Invalid URL");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto mt-10 p-5 bg-white shadow-xl rounded-2xl">
      
      <h2 className="text-2xl font-bold mb-4 text-center">
        Check Website Port
      </h2>

      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          type="text"
          placeholder="Enter website (e.g. google.com)"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          className="flex-1 p-2 border rounded-lg"
        />
        <button
          type="submit"
          className="bg-blue-500 text-white px-4 rounded-lg"
        >
          {loading ? "Checking..." : "Check"}
        </button>
      </form>

      {error && (
        <p className="text-red-500 mt-2 text-center">{error}</p>
      )}

      {/* <h3 className="mt-6 text-lg font-semibold">History</h3>

      <div className="mt-3 space-y-2">
        {data.map((item) => (
          <div
            key={item._id}
            className="p-3 bg-gray-100 rounded-lg flex justify-between"
          >
            <span>{item.url}</span>
            <span className="font-bold text-blue-600">
              Port: {item.port}
            </span>
          </div>
        ))}
      </div> */
      
      }
    </div>
  );
};

export default PortForm;
